/**
 * PressVideo — Offcanvas drawer controller.
 * Vanilla JS. No jQuery, no Bootstrap.
 */
(function () {
    'use strict';

    var cfg     = window.pvOffcanvas || {};
    var ajaxUrl = cfg.ajaxUrl || '';
    var SPEEDS  = [0.5, 0.75, 1, 1.25, 1.5, 2];

    // DOM refs
    var canvas, panel, backdrop, closeBtn, titleEl, descEl, badgeEl,
        iframeHolder, navCount, prevBtn, nextBtn, railEl,
        autoplayToggle, loopBtn, shuffleBtn, speedBtn,
        searchInput, searchClearBtn, searchWrap, searchMicBtn,
        socialYt, socialX, socialFb;

    // Playback state
    var playlist = [], current = 0, anchorId = '';
    var railPage = 0, railMaxPages = 0, railBusy = false;
    var railSentinel = null, railObserver = null;
    var queue         = [];
    var continuousPlay = localStorage.getItem('pv_continuous_play') !== 'false';
    var loopActive    = false;
    var shuffleActive = false;
    var originalPlaylist = [];
    var currentSpeed  = parseFloat(localStorage.getItem('pv_speed') || '1') || 1;
    var activeMenu    = null;
    var speedMenuEl   = null;
    var toastTimer    = null;
    var resumeToastTimer = null;

    /* ── Init ─────────────────────────────────────────────────── */
    function init() {
        canvas = document.getElementById('pv-canvas');
        if (!canvas) return;

        panel         = canvas.querySelector('.pv-panel');
        backdrop      = canvas.querySelector('.pv-backdrop');
        closeBtn      = canvas.querySelector('.pv-close');
        titleEl       = canvas.querySelector('.pv-title');
        descEl        = canvas.querySelector('.pv-desc');
        badgeEl       = canvas.querySelector('.pv-playlist-label');
        iframeHolder  = canvas.querySelector('.pv-iframe-holder');
        navCount      = canvas.querySelector('.pv-nav-count');
        prevBtn       = canvas.querySelector('.pv-prev');
        nextBtn       = canvas.querySelector('.pv-next');
        railEl        = canvas.querySelector('.pv-rail');
        autoplayToggle = canvas.querySelector('.pv-autoplay-toggle');
        loopBtn       = canvas.querySelector('.pv-loop-btn');
        shuffleBtn    = canvas.querySelector('.pv-shuffle-btn');
        speedBtn      = canvas.querySelector('.pv-speed-btn');
        searchInput    = canvas.querySelector('.pv-rail-search__input');
        searchClearBtn = canvas.querySelector('.pv-rail-search__clear');
        searchWrap     = canvas.querySelector('.pv-rail-search');
        searchMicBtn   = canvas.querySelector('.pv-rail-search__mic');
        socialYt  = canvas.querySelector('.pv-social-btn--yt');
        socialX   = canvas.querySelector('.pv-social-btn--x');
        socialFb  = canvas.querySelector('.pv-social-btn--fb');

        document.addEventListener('click', onTriggerClick);
        document.addEventListener('click', onDocClick);

        if (closeBtn)   closeBtn.addEventListener('click', close);
        if (backdrop)   backdrop.addEventListener('click', close);

        if (autoplayToggle) {
            syncAutoplayToggle();
            autoplayToggle.addEventListener('click', function () {
                continuousPlay = !continuousPlay;
                localStorage.setItem('pv_continuous_play', continuousPlay ? 'true' : 'false');
                syncAutoplayToggle();
            });
        }

        if (loopBtn)    loopBtn.addEventListener('click', toggleLoop);
        if (shuffleBtn) shuffleBtn.addEventListener('click', toggleShuffle);
        if (speedBtn)   { syncSpeedBtn(); speedBtn.addEventListener('click', function (e) { e.stopPropagation(); openSpeedMenu(); }); }

        if (searchInput) {
            searchInput.addEventListener('input', onSearchInput);
            searchInput.addEventListener('keydown', function (e) {
                if (e.key === 'Escape') { clearSearch(); searchInput.blur(); }
            });
        }
        if (searchClearBtn) searchClearBtn.addEventListener('click', clearSearch);

        // Voice search
        if (searchMicBtn) {
            var SR = window.SpeechRecognition || window.webkitSpeechRecognition;
            if (SR) {
                var recognition = new SR();
                recognition.continuous = false;
                recognition.interimResults = false;
                recognition.lang = 'en-US';
                var micActive = false;
                searchMicBtn.addEventListener('click', function () {
                    if (micActive) { recognition.stop(); }
                    else { try { recognition.start(); } catch (e) {} }
                });
                recognition.addEventListener('start', function () {
                    micActive = true;
                    searchMicBtn.classList.add('pv-rail-search__mic--active');
                });
                recognition.addEventListener('end', function () {
                    micActive = false;
                    searchMicBtn.classList.remove('pv-rail-search__mic--active');
                });
                recognition.addEventListener('result', function (e) {
                    var transcript = e.results[0][0].transcript;
                    if (searchInput) { searchInput.value = transcript; onSearchInput(); }
                });
                recognition.addEventListener('error', function () {
                    micActive = false;
                    searchMicBtn.classList.remove('pv-rail-search__mic--active');
                });
            } else {
                searchMicBtn.style.display = 'none';
            }
        }

        canvas.addEventListener('pv:video-ended', onVideoEnded);
        canvas.addEventListener('pv:player-ready', onPlayerReady);
        canvas.addEventListener('pv:progress-updated', onProgressUpdated);

        document.addEventListener('keydown', function (e) {
            if (!canvas.classList.contains('pv-open')) return;
            if (e.key === 'Escape') {
                e.preventDefault();
                if (activeMenu || speedMenuEl) { closeMenu(); closeSpeedMenu(); }
                else { close(); }
            }
            if (e.key === 'ArrowRight') { e.preventDefault(); navigate(1); }
            if (e.key === 'ArrowLeft')  { e.preventDefault(); navigate(-1); }
        });

        if (prevBtn) prevBtn.addEventListener('click', function () { navigate(-1); });
        if (nextBtn) nextBtn.addEventListener('click', function () { navigate(1); });

        initSwipe();
    }

    /* ── Autoplay toggle ──────────────────────────────────────── */
    function syncAutoplayToggle() {
        if (!autoplayToggle) return;
        autoplayToggle.classList.toggle('pv-autoplay-toggle--on', continuousPlay);
        autoplayToggle.setAttribute('aria-pressed', String(continuousPlay));
    }

    /* ── Loop toggle ──────────────────────────────────────────── */
    function toggleLoop() {
        loopActive = !loopActive;
        if (loopBtn) {
            loopBtn.classList.toggle('pv-loop-btn--on', loopActive);
            loopBtn.setAttribute('aria-pressed', String(loopActive));
        }
        showToast(loopActive ? 'Loop on' : 'Loop off');
    }

    /* ── Shuffle toggle ───────────────────────────────────────── */
    function toggleShuffle() {
        shuffleActive = !shuffleActive;
        if (shuffleBtn) {
            shuffleBtn.classList.toggle('pv-shuffle-btn--on', shuffleActive);
            shuffleBtn.setAttribute('aria-pressed', String(shuffleActive));
        }
        queue = [];
        if (shuffleActive) {
            originalPlaylist = playlist.slice();
            var cur = playlist[current];
            for (var i = playlist.length - 1; i > 0; i--) {
                var j = Math.floor(Math.random() * (i + 1));
                var t = playlist[i]; playlist[i] = playlist[j]; playlist[j] = t;
            }
            // Keep current video first after shuffle
            var ni = playlist.findIndex(function (v) { return v.youtubeId === (cur && cur.youtubeId); });
            if (ni > 0) { var tmp = playlist[0]; playlist[0] = playlist[ni]; playlist[ni] = tmp; }
            current = 0;
        } else {
            var curSlide = playlist[current];
            playlist = originalPlaylist.slice();
            current = playlist.findIndex(function (v) { return v.youtubeId === (curSlide && curSlide.youtubeId); });
            if (current < 0) current = 0;
        }
        rebuildRail();
        showToast(shuffleActive ? 'Shuffle on' : 'Shuffle off');
    }

    function rebuildRail() {
        if (!railEl) return;
        railEl.innerHTML = '';
        playlist.forEach(function (slide, i) { railEl.appendChild(makeRailItem(slide, i)); });
        updateRail(current);
        updateNav();
    }

    /* ── Speed control ────────────────────────────────────────── */
    function syncSpeedBtn() {
        if (!speedBtn) return;
        var lbl = speedBtn.querySelector('.pv-speed-btn__label');
        if (lbl) lbl.textContent = currentSpeed === 1 ? '1×' : currentSpeed + '×';
        speedBtn.classList.toggle('pv-speed-btn--active', currentSpeed !== 1);
    }

    function openSpeedMenu() {
        if (speedMenuEl) { closeSpeedMenu(); return; }
        var menu = document.createElement('div');
        menu.className = 'pv-speed-menu';
        menu.setAttribute('role', 'menu');
        SPEEDS.forEach(function (rate) {
            var btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'pv-speed-menu__item' + (rate === currentSpeed ? ' pv-speed-menu__item--active' : '');
            btn.setAttribute('role', 'menuitem');
            btn.textContent = rate === 1 ? 'Normal' : rate + '×';
            btn.addEventListener('click', function (e) { e.stopPropagation(); setSpeed(rate); closeSpeedMenu(); });
            menu.appendChild(btn);
        });
        var rect = speedBtn.getBoundingClientRect();
        menu.style.left   = rect.left + 'px';
        menu.style.bottom = (window.innerHeight - rect.top + 4) + 'px';
        document.body.appendChild(menu);
        speedMenuEl = menu;
        requestAnimationFrame(function () {
            var mr = menu.getBoundingClientRect();
            if (mr.top < 8) { menu.style.bottom = 'auto'; menu.style.top = (rect.bottom + 4) + 'px'; }
            if (mr.right > window.innerWidth - 8) { menu.style.left = 'auto'; menu.style.right = '8px'; }
        });
    }

    function closeSpeedMenu() {
        if (speedMenuEl && speedMenuEl.parentNode) speedMenuEl.parentNode.removeChild(speedMenuEl);
        speedMenuEl = null;
    }

    function setSpeed(rate) {
        currentSpeed = rate;
        localStorage.setItem('pv_speed', String(rate));
        canvas.dispatchEvent(new CustomEvent('pv:set-speed', { bubbles: false, detail: { rate: rate } }));
        syncSpeedBtn();
    }

    /* ── Progress helpers ─────────────────────────────────────── */
    function getProgress() {
        try { return JSON.parse(localStorage.getItem('pv_progress') || '{}'); } catch (e) { return {}; }
    }

    function formatTime(sec) {
        sec = Math.floor(sec);
        var m = Math.floor(sec / 60), s = sec % 60;
        return m + ':' + (s < 10 ? '0' : '') + s;
    }

    /* ── Resume playback ──────────────────────────────────────── */
    function onPlayerReady(e) {
        var d = e.detail || {};
        if (d.savedPct > 0.03 && d.savedPct < 0.95) {
            showResumeToast(d.savedSec);
        }
        // Re-apply persisted speed to new player instance
        if (currentSpeed !== 1) {
            canvas.dispatchEvent(new CustomEvent('pv:set-speed', { bubbles: false, detail: { rate: currentSpeed } }));
        }
    }

    function showResumeToast(sec) {
        var old = document.getElementById('pv-resume-toast');
        if (old) { dismissResumeToast(old); }
        clearTimeout(resumeToastTimer);
        var toast = document.createElement('div');
        toast.id = 'pv-resume-toast';
        toast.setAttribute('role', 'status');
        toast.innerHTML =
            '<span>Resume from ' + formatTime(sec) + '?</span>' +
            '<button class="pv-resume-toast__btn" type="button">Resume</button>' +
            '<button class="pv-resume-toast__dismiss" type="button" aria-label="Dismiss">' +
            '<svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><path d="M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z"/></svg>' +
            '</button>';
        document.body.appendChild(toast);
        requestAnimationFrame(function () { toast.classList.add('pv-resume-toast--show'); });
        toast.querySelector('.pv-resume-toast__btn').addEventListener('click', function () {
            canvas.dispatchEvent(new CustomEvent('pv:seek-to', { bubbles: false, detail: { seconds: sec } }));
            dismissResumeToast(toast);
        });
        toast.querySelector('.pv-resume-toast__dismiss').addEventListener('click', function () {
            dismissResumeToast(toast);
        });
        resumeToastTimer = setTimeout(function () { dismissResumeToast(toast); }, 7000);
    }

    function dismissResumeToast(toast) {
        clearTimeout(resumeToastTimer);
        if (!toast || !toast.parentNode) return;
        toast.classList.remove('pv-resume-toast--show');
        setTimeout(function () { if (toast.parentNode) toast.remove(); }, 280);
    }

    /* ── Progress bar live update ─────────────────────────────── */
    function onProgressUpdated(e) {
        if (!railEl) return;
        var d = e.detail || {};
        var active = railEl.querySelector('.pv-rail__item--active');
        if (!active) return;
        var fill = active.querySelector('.pv-rail__progress-fill');
        if (fill && d.pct > 0) fill.style.width = Math.min(d.pct * 100, 100).toFixed(1) + '%';
    }

    /* ── Search / filter ──────────────────────────────────────── */
    function onSearchInput() {
        var q = (searchInput.value || '').trim().toLowerCase();
        if (searchClearBtn) searchClearBtn.hidden = !q;
        filterRail(q);
    }

    function clearSearch() {
        if (searchInput) searchInput.value = '';
        if (searchClearBtn) searchClearBtn.hidden = true;
        filterRail('');
    }

    function filterRail(q) {
        if (!railEl) return;
        var count = 0;
        railEl.querySelectorAll('.pv-rail__item').forEach(function (el, i) {
            var title = (playlist[i] && playlist[i].title) || '';
            var show = !q || title.toLowerCase().indexOf(q) >= 0;
            el.style.display = show ? '' : 'none';
            if (show) count++;
        });
        var noRes = railEl.querySelector('.pv-rail__no-results');
        if (!noRes) {
            noRes = document.createElement('p');
            noRes.className = 'pv-rail__no-results';
            railEl.appendChild(noRes);
        }
        noRes.textContent = (q && count === 0) ? 'No results for “' + q + '”' : '';
        noRes.style.display = (q && count === 0) ? '' : 'none';
    }

    /* ── Swipe to close (mobile) ──────────────────────────────── */
    function initSwipe() {
        if (!panel) return;
        var sx = 0, sy = 0, dx = 0, dy = 0, active = false;
        panel.addEventListener('touchstart', function (e) {
            var t = e.touches[0];
            sx = t.clientX; sy = t.clientY; dx = 0; dy = 0; active = true;
            panel.style.transition = 'none';
        }, { passive: true });
        panel.addEventListener('touchmove', function (e) {
            if (!active) return;
            var t = e.touches[0];
            dx = t.clientX - sx; dy = t.clientY - sy;
            if (window.innerWidth <= 767 && dy > 0 && dy > Math.abs(dx)) {
                panel.style.transform = 'translateY(' + dy + 'px)';
            } else if (window.innerWidth > 767 && dx > 0 && dx > Math.abs(dy)) {
                panel.style.transform = 'translateX(' + dx + 'px)';
            }
        }, { passive: true });
        panel.addEventListener('touchend', function () {
            if (!active) return;
            active = false;
            panel.style.transition = '';
            panel.style.transform  = '';
            if ((window.innerWidth <= 767 && dy > 80) || (window.innerWidth > 767 && dx > 80)) { close(); }
        }, { passive: true });
        panel.addEventListener('touchcancel', function () {
            active = false;
            panel.style.transition = '';
            panel.style.transform  = '';
        }, { passive: true });
    }

    /* ── Video ended ──────────────────────────────────────────── */
    function onVideoEnded() {
        if (loopActive) {
            canvas.dispatchEvent(new CustomEvent('pv:seek-to', { bubbles: false, detail: { seconds: 0 } }));
            return;
        }
        if (!continuousPlay) return;
        if (queue.length > 0) {
            var next = queue.shift();
            updateQueueBadges();
            updateNav();
            navigateTo(next);
        } else if (current < playlist.length - 1) {
            navigateTo(current + 1);
        }
    }

    /* ── Outside click ────────────────────────────────────────── */
    function onDocClick(e) {
        if (activeMenu && !e.target.closest('.pv-rail__menu') && !e.target.closest('.pv-rail__menu-btn')) closeMenu();
        if (speedMenuEl && !e.target.closest('.pv-speed-menu') && !e.target.closest('.pv-speed-btn')) closeSpeedMenu();
    }

    /* ── Trigger click ────────────────────────────────────────── */
    function onTriggerClick(e) {
        var trigger = e.target.closest('.pv-trigger');
        if (!trigger) return;
        e.preventDefault();
        e.stopPropagation();
        anchorId = trigger.dataset.youtubeId || '';
        queue = [];
        var plRaw = trigger.dataset.playlist || '';
        var plData = null;
        try { plData = plRaw ? JSON.parse(plRaw) : null; } catch (err) { plData = null; }

        if (plData && plData.length > 0 && !document.body.dataset.pvActivePl) {
            playlist = plData;
            current  = playlist.findIndex(function (v) { return v.youtubeId === anchorId; });
            if (current < 0) current = 0;
            loadSlide(current);
            open();
            buildRailFromData(playlist);
        } else {
            playlist = [{ youtubeId: anchorId, embedUrl: trigger.dataset.embedUrl || '', title: trigger.dataset.title || '', desc: trigger.dataset.description || '', accent: trigger.dataset.accent || '#4f46e5', thumb: '', duration: '', permalink: trigger.dataset.permalink || '' }];
            current = 0;
            loadSlide(0);
            open();
            resetRail();
            fetchRailPage(1);
        }
    }

    /* ── Rail management ──────────────────────────────────────── */
    function resetRail() {
        railPage = 0; railMaxPages = 0; railBusy = false;
        clearSearch();
        detachSentinel();
        if (!railEl) return;
        railEl.innerHTML = '';
        railEl.style.display = '';
        if (searchWrap) searchWrap.style.display = 'none';
        var el = document.createElement('div');
        el.className = 'pv-rail__loading';
        el.innerHTML = '<span class="pv-rail__spinner"></span>';
        railEl.appendChild(el);
    }

    function buildRailFromData(data) {
        railPage = 1; railMaxPages = 1; railBusy = false;
        clearSearch();
        detachSentinel();
        if (!railEl) return;
        railEl.innerHTML = '';
        var show = data.length > 1;
        railEl.style.display = show ? '' : 'none';
        if (searchWrap) searchWrap.style.display = (show && data.length >= 5) ? '' : 'none';
        if (!show) return;
        data.forEach(function (slide, i) { railEl.appendChild(makeRailItem(slide, i)); });
        updateNav();
        updateRail(current);
    }

    function fetchRailPage(page) {
        if (railBusy) return;
        if (railMaxPages > 0 && page > railMaxPages) return;
        if (!ajaxUrl) { if (railEl) railEl.style.display = 'none'; return; }
        railBusy = true;
        var activePl = document.body.dataset.pvActivePl || '';
        var url = ajaxUrl + '?action=pv_playlist_page&page=' + page + (activePl ? '&pv_yt_pl=' + encodeURIComponent(activePl) : '');
        fetch(url).then(function (r) { return r.json(); }).then(function (data) {
            if (!data || !data.success) return;
            var res = data.data;
            railPage    = res.page;
            railMaxPages = res.maxPages;
            if (page === 1) {
                playlist = res.items;
                current  = playlist.findIndex(function (v) { return v.youtubeId === anchorId; });
                if (current < 0) current = 0;
                if (!railEl) return;
                railEl.innerHTML = '';
                var show = playlist.length > 1;
                railEl.style.display = show ? '' : 'none';
                if (searchWrap) searchWrap.style.display = (show && playlist.length >= 5) ? '' : 'none';
                if (!show) return;
                playlist.forEach(function (slide, i) { railEl.appendChild(makeRailItem(slide, i)); });
            } else {
                var off = playlist.length;
                playlist = playlist.concat(res.items);
                res.items.forEach(function (slide, i) { railEl.insertBefore(makeRailItem(slide, off + i), railSentinel || null); });
                if (searchWrap && playlist.length >= 5) searchWrap.style.display = '';
            }
            updateNav();
            updateRail(current);
            if (railPage < railMaxPages) attachSentinel(); else detachSentinel();
        }).catch(function () { if (railEl) railEl.style.display = 'none'; })
          .finally(function () { railBusy = false; });
    }

    /* ── Rail item factory ────────────────────────────────────── */
    function makeRailItem(slide, idx) {
        var item = document.createElement('div');
        item.className = 'pv-rail__item' + (idx === current ? ' pv-rail__item--active' : '');
        item.setAttribute('role', 'listitem');
        item.setAttribute('tabindex', '0');
        item.setAttribute('aria-label', slide.title || ('Video ' + (idx + 1)));
        item.setAttribute('aria-current', idx === current ? 'true' : 'false');

        var thumbInner = slide.thumb
            ? '<img class="pv-rail__thumb" src="' + esc(slide.thumb) + '" alt="" loading="lazy">'
            : '<div class="pv-rail__thumb pv-rail__thumb--placeholder"></div>';

        var durBadge = slide.duration ? '<span class="pv-rail__dur-badge">' + esc(slide.duration) + '</span>' : '';

        // Watch progress
        var prog  = getProgress();
        var pdata = prog[slide.youtubeId];
        var pct   = pdata && pdata.pct > 0.02 ? Math.min(pdata.pct, 1) : 0;
        var fill  = pct > 0 ? ' style="width:' + (pct * 100).toFixed(1) + '%;background:' + (pdata.pct >= 0.95 ? 'rgba(255,255,255,.22)' : 'var(--pv-accent)') + '"' : '';
        var progressBar = '<div class="pv-rail__progress"><div class="pv-rail__progress-fill"' + fill + '></div></div>';

        if (pdata && pdata.pct >= 0.95) item.classList.add('pv-rail__item--watched');

        item.innerHTML =
            '<div class="pv-rail__thumb-wrap">' + thumbInner + durBadge + progressBar + '</div>' +
            '<div class="pv-rail__info"><div class="pv-eq" aria-hidden="true"><span></span><span></span><span></span></div>' +
            '<p class="pv-rail__title">' + esc(slide.title) + '</p></div>' +
            '<div class="pv-rail__actions"><button class="pv-rail__menu-btn" type="button" aria-label="More options" aria-haspopup="true">' +
            '<svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg>' +
            '</button></div>';

        item.addEventListener('click', (function (i) {
            return function (e) { if (e.target.closest('.pv-rail__menu-btn') || e.target.closest('.pv-rail__menu')) return; navigateTo(i); };
        }(idx)));
        item.addEventListener('keydown', (function (i) {
            return function (e) { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); navigateTo(i); } };
        }(idx)));
        var menuBtn = item.querySelector('.pv-rail__menu-btn');
        menuBtn.addEventListener('click', (function (s, i, btn) {
            return function (e) {
                e.stopPropagation();
                if (activeMenu && activeMenu.dataset.forIdx === String(i)) closeMenu();
                else openMenu(s, i, btn);
            };
        }(slide, idx, menuBtn)));
        return item;
    }

    /* ── Three-dot menu ───────────────────────────────────────── */
    function openMenu(slide, idx, anchor) {
        closeMenu();
        var inQ  = queue.indexOf(idx) >= 0;
        var inWL = isWatchLater(slide.youtubeId);
        var menu = document.createElement('div');
        menu.className   = 'pv-rail__menu';
        menu.dataset.forIdx = String(idx);
        menu.setAttribute('role', 'menu');
        var items = [
            { svg: '<path d="M19 3H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm-2 10h-4v4h-2v-4H7v-2h4V7h2v4h4v2z"/>',
              label: inQ  ? 'Remove from Queue'       : 'Add to Queue',       action: function () { toggleQueue(idx); closeMenu(); } },
            { svg: '<path d="M17 3H7c-1.1 0-2 .9-2 2v16l7-3 7 3V5c0-1.1-.9-2-2-2z"/>',
              label: inWL ? 'Remove from Watch Later' : 'Save to Watch Later', action: function () { toggleWatchLater(slide, idx); closeMenu(); } },
            { svg: '<path d="M18 16.08c-.76 0-1.44.3-1.96.77L8.91 12.7c.05-.23.09-.46.09-.7s-.04-.47-.09-.7l7.05-4.11c.54.5 1.25.81 2.04.81 1.66 0 3-1.34 3-3s-1.34-3-3-3-3 1.34-3 3c0 .24.04.47.09.7L8.04 9.81C7.5 9.31 6.79 9 6 9c-1.66 0-3 1.34-3 3s1.34 3 3 3c.79 0 1.5-.31 2.04-.81l7.12 4.16c-.05.21-.08.43-.08.65 0 1.61 1.31 2.92 2.92 2.92 1.61 0 2.92-1.31 2.92-2.92s-1.31-2.92-2.92-2.92z"/>',
              label: 'Share', action: function () { shareVideo(slide); closeMenu(); } }
        ];
        items.forEach(function (it) {
            var btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'pv-rail__menu-item';
            btn.setAttribute('role', 'menuitem');
            btn.innerHTML = '<svg width="15" height="15" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">' + it.svg + '</svg><span>' + esc(it.label) + '</span>';
            btn.addEventListener('click', it.action);
            menu.appendChild(btn);
        });
        var rect = anchor.getBoundingClientRect();
        menu.style.top   = (rect.bottom + 4) + 'px';
        menu.style.right = (window.innerWidth - rect.right) + 'px';
        document.body.appendChild(menu);
        activeMenu = menu;
        requestAnimationFrame(function () {
            var mr = menu.getBoundingClientRect();
            if (mr.bottom > window.innerHeight - 8) { menu.style.top = 'auto'; menu.style.bottom = (window.innerHeight - rect.top + 4) + 'px'; }
            if (mr.left < 8) { menu.style.right = 'auto'; menu.style.left = '8px'; }
        });
    }

    function closeMenu() {
        if (activeMenu && activeMenu.parentNode) activeMenu.parentNode.removeChild(activeMenu);
        activeMenu = null;
    }

    /* ── Queue ────────────────────────────────────────────────── */
    function toggleQueue(idx) {
        var pos = queue.indexOf(idx);
        if (pos >= 0) { queue.splice(pos, 1); showToast('Removed from queue'); }
        else          { queue.push(idx);       showToast('Added to queue'); }
        updateQueueBadges();
        updateNav();
    }

    function updateQueueBadges() {
        if (!railEl) return;
        railEl.querySelectorAll('.pv-rail__item').forEach(function (el, i) {
            var pos   = queue.indexOf(i);
            var wrap  = el.querySelector('.pv-rail__thumb-wrap');
            var badge = el.querySelector('.pv-rail__queue-badge');
            if (pos >= 0) {
                if (!badge) { badge = document.createElement('span'); badge.className = 'pv-rail__queue-badge'; if (wrap) wrap.appendChild(badge); }
                badge.textContent = pos + 1;
            } else if (badge) { badge.remove(); }
        });
    }

    /* ── Watch Later ──────────────────────────────────────────── */
    function getWatchLater() {
        try { return JSON.parse(localStorage.getItem('pv_watch_later') || '[]'); } catch (e) { return []; }
    }
    function isWatchLater(id) { return getWatchLater().some(function (v) { return v.youtubeId === id; }); }
    function toggleWatchLater(slide) {
        var list = getWatchLater();
        var pos  = list.findIndex(function (v) { return v.youtubeId === slide.youtubeId; });
        var adding = pos < 0;
        if (adding) list.push({ youtubeId: slide.youtubeId, title: slide.title, thumb: slide.thumb, embedUrl: slide.embedUrl, permalink: slide.permalink || '' });
        else list.splice(pos, 1);
        localStorage.setItem('pv_watch_later', JSON.stringify(list));
        showToast(adding ? 'Saved to Watch Later' : 'Removed from Watch Later');
    }

    /* ── Share ────────────────────────────────────────────────── */
    function shareVideo(slide) {
        var url   = slide.permalink || window.location.href;
        var title = slide.title || 'Watch this video';
        if (navigator.share)     { navigator.share({ title: title, url: url }).catch(function () {}); return; }
        if (navigator.clipboard) { navigator.clipboard.writeText(url).then(function () { showToast('Link copied to clipboard'); }).catch(function () { fallbackCopy(url); }); return; }
        fallbackCopy(url);
    }
    function fallbackCopy(text) {
        var ta = document.createElement('textarea');
        ta.value = text; ta.style.cssText = 'position:fixed;opacity:0;pointer-events:none';
        document.body.appendChild(ta); ta.select();
        try { document.execCommand('copy'); showToast('Link copied to clipboard'); } catch (e) { showToast('Copy failed — try manually'); }
        document.body.removeChild(ta);
    }

    /* ── Toast ────────────────────────────────────────────────── */
    function showToast(msg) {
        var toast = document.getElementById('pv-toast');
        if (!toast) {
            toast = document.createElement('div');
            toast.id = 'pv-toast';
            toast.setAttribute('role', 'status');
            toast.setAttribute('aria-live', 'polite');
            document.body.appendChild(toast);
        }
        toast.textContent = msg;
        toast.classList.add('pv-toast--show');
        clearTimeout(toastTimer);
        toastTimer = setTimeout(function () { toast.classList.remove('pv-toast--show'); }, 2200);
    }

    /* ── Open / close ─────────────────────────────────────────── */
    function open() {
        canvas.classList.add('pv-open');
        canvas.setAttribute('aria-hidden', 'false');
        document.body.style.overflow = 'hidden';
        if (closeBtn) requestAnimationFrame(function () { closeBtn.focus(); });
        canvas.dispatchEvent(new CustomEvent('pv:opened', { bubbles: true }));
    }

    function close() {
        canvas.classList.remove('pv-open');
        canvas.setAttribute('aria-hidden', 'true');
        document.body.style.overflow = '';
        closeMenu();
        closeSpeedMenu();
        var rt = document.getElementById('pv-resume-toast');
        if (rt) dismissResumeToast(rt);
        canvas.dispatchEvent(new CustomEvent('pv:closed', { bubbles: true }));
    }

    /* ── Load slide ───────────────────────────────────────────── */
    function loadSlide(index) {
        var slide = playlist[index];
        if (!slide) return;
        canvas.style.setProperty('--pv-accent', slide.accent || '#4f46e5');
        if (titleEl) titleEl.textContent = slide.title || '';
        if (descEl)  descEl.textContent  = slide.desc  || '';
        if (badgeEl) {
            var pt = document.body.dataset.pvActivePlTitle || '';
            badgeEl.textContent   = pt ? (/videos?$/i.test(pt) ? pt : pt + ' Videos') : '';
            badgeEl.style.display = pt ? '' : 'none';
        }
        if (iframeHolder) { iframeHolder.dataset.embedUrl = slide.embedUrl || ''; delete iframeHolder.dataset.loaded; }

        // Social share links
        var ytId      = slide.youtubeId || '';
        var permalink = slide.permalink || window.location.href;
        var title     = slide.title || 'Watch this video';
        if (socialYt) socialYt.href = ytId ? 'https://www.youtube.com/watch?v=' + ytId : '#';
        if (socialX)  socialX.href  = 'https://twitter.com/intent/tweet?url=' + encodeURIComponent(permalink) + '&text=' + encodeURIComponent(title);
        if (socialFb) socialFb.href = 'https://www.facebook.com/sharer/sharer.php?u=' + encodeURIComponent(permalink);

        updateNav();
        updateRail(index);
        canvas.dispatchEvent(new CustomEvent('pv:slide-changed', { bubbles: true, detail: { index: index, slide: slide } }));
    }

    /* ── Navigation ───────────────────────────────────────────── */
    function navigate(delta) {
        if (delta === 1 && queue.length > 0) {
            var ni = queue.shift(); updateQueueBadges(); updateNav(); navigateTo(ni);
        } else { navigateTo(current + delta); }
    }

    function navigateTo(index) {
        if (index < 0 || index >= playlist.length || index === current) return;
        current = index;
        canvas.dispatchEvent(new CustomEvent('pv:closed',  { bubbles: false }));
        loadSlide(current);
        canvas.dispatchEvent(new CustomEvent('pv:opened',  { bubbles: false }));
    }

    function updateNav() {
        var hasNext = current < playlist.length - 1 || queue.length > 0;
        if (navCount) {
            var qs = queue.length > 0 ? ' · Queue: ' + queue.length : '';
            navCount.textContent = playlist.length > 1 ? (current + 1) + ' / ' + playlist.length + qs : (qs || '');
        }
        if (prevBtn) prevBtn.disabled = (current === 0);
        if (nextBtn) nextBtn.disabled = !hasNext;
    }

    function updateRail(index) {
        if (!railEl || railEl.style.display === 'none') return;
        railEl.querySelectorAll('.pv-rail__item').forEach(function (el, i) {
            var on = (i === index);
            el.classList.toggle('pv-rail__item--active', on);
            el.setAttribute('aria-current', on ? 'true' : 'false');
        });
        var active = railEl.querySelectorAll('.pv-rail__item')[index];
        if (active) active.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    }

    /* ── Sentinel / infinite scroll ───────────────────────────── */
    function attachSentinel() {
        if (!railEl) return;
        if (!railSentinel) { railSentinel = document.createElement('div'); railSentinel.className = 'pv-rail__sentinel'; }
        railEl.appendChild(railSentinel);
        if ('IntersectionObserver' in window && panel) {
            if (railObserver) railObserver.disconnect();
            railObserver = new IntersectionObserver(function (entries) {
                if (entries[0].isIntersecting && !railBusy) fetchRailPage(railPage + 1);
            }, { root: panel, rootMargin: '150px' });
            railObserver.observe(railSentinel);
        }
    }

    function detachSentinel() {
        if (railObserver) { railObserver.disconnect(); railObserver = null; }
        if (railSentinel && railSentinel.parentNode) { railSentinel.parentNode.removeChild(railSentinel); railSentinel = null; }
    }

    /* ── Escape utility ───────────────────────────────────────── */
    function esc(str) {
        return String(str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    }

    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
    else init();
}());
